{"request":{"code":"python3 -c '
import zipfile

xlsx_path = "/filesystem/01. Model/DCF_v11.xlsx"
keywords = ["PE", "P/E", "earnings", "EPS", "sector", "comm"]
found = []
with zipfile.ZipFile(xlsx_path, "r") as z:
    for name in z.namelist():
        if name.endswith(".xml"):
            try:
                content = z.read(name).decode("utf-8", errors="ignore")
                for kw in keywords:
                    if kw.lower() in content.lower():
                        idx = content.lower().find(kw.lower())
                        snippet = content[max(0,idx-20):idx+80]
                        found.append((kw, name, snippet))
                        break
            except:
                pass
print("Found", len(found), "matches")
for item in found[:5]:
    print(item)
